using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

// --- Build the AI chat client with automatic tool invocation ---
var tools = new ResearchTools();

IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(modelName)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(tools.SearchWeb),
        AIFunctionFactory.Create(tools.ReadWebPage),
        AIFunctionFactory.Create(tools.SaveNote),
        AIFunctionFactory.Create(tools.GetNotes),
    ]
};

const string SystemPrompt = """
    You are a research agent. Your job is to research a topic thoroughly using the
    available tools, then deliver a well-structured summary.

    Workflow:
    1. SearchWeb – find relevant sources for the topic.
    2. ReadWebPage – read the most promising pages for details.
    3. SaveNote – record every important finding (facts, statistics, quotes).
    4. GetNotes – retrieve your notes, then write a comprehensive summary.

    Be thorough but efficient. Aim for at least 3 different sources.
    """;

// --- Get topic from user ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Run the agent loop (tool calls are handled automatically) ---
List<ChatMessage> messages =
[
    new(ChatRole.System, SystemPrompt),
    new(ChatRole.User,
        $"Research the following topic and provide a comprehensive summary: {topic}")
];

var response = await client.GetResponseAsync(messages, chatOptions);

Console.WriteLine("\n📋 Research Summary:");
Console.WriteLine(new string('─', 60));
Console.WriteLine(response.Text);
Console.WriteLine(new string('─', 60));
Console.WriteLine($"📝 Notes collected during research: {tools.NoteCount}");

// ---------------------------------------------------------------------------
// Tool implementations
// ---------------------------------------------------------------------------

partial class ResearchTools
{
    private readonly HttpClient _http = new()
    {
        DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } },
        Timeout = TimeSpan.FromSeconds(15)
    };

    private readonly List<string> _notes = [];
    public int NoteCount => _notes.Count;

    [Description("Search the web for a query. Returns titles, URLs, and snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🌐 Searching: {query}");
        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var html = await _http.GetStringAsync(
                $"https://lite.duckduckgo.com/lite/?q={encoded}");

            var results = ParseSearchResults(html);
            if (results.Count == 0)
                return "No results found.";

            var sb = new StringBuilder();
            foreach (var (title, url, snippet) in results.Take(8))
            {
                sb.AppendLine($"Title: {title}");
                sb.AppendLine($"URL: {url}");
                sb.AppendLine($"Snippet: {snippet}");
                sb.AppendLine();
            }
            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch and read the text content of a web page at the given URL.")]
    public async Task<string> ReadWebPage(
        [Description("The full URL to read")] string url)
    {
        Console.WriteLine($"  📄 Reading: {url}");
        try
        {
            var html = await _http.GetStringAsync(url);
            var text = StripHtml(html);
            return text.Length > 5000
                ? string.Concat(text.AsSpan(0, 5000), "\n[…truncated]")
                : text;
        }
        catch (Exception ex)
        {
            return $"Failed to read page: {ex.Message}";
        }
    }

    [Description("Save a research note. Use this to record important findings.")]
    public string SaveNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 Note saved ({_notes.Count} total)");
        return $"Note saved. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
            sb.AppendLine($"--- Note {i + 1} ---\n{_notes[i]}\n");
        return sb.ToString();
    }

    // --- Helpers ---

    private static List<(string Title, string Url, string Snippet)> ParseSearchResults(
        string html)
    {
        var results = new List<(string, string, string)>();

        var linkRx = new Regex(
            @"<a[^>]+rel=""nofollow""[^>]+href=""([^""]+)""[^>]*>(.+?)</a>",
            RegexOptions.Singleline);
        var snippetRx = new Regex(
            @"<td\s+class=""result-snippet"">(.+?)</td>",
            RegexOptions.Singleline);

        var links = linkRx.Matches(html);
        var snippets = snippetRx.Matches(html);

        for (var i = 0; i < links.Count && i < snippets.Count; i++)
        {
            var url = WebUtility.HtmlDecode(links[i].Groups[1].Value).Trim();
            var title = StripHtml(links[i].Groups[2].Value).Trim();
            var snippet = StripHtml(snippets[i].Groups[1].Value).Trim();

            if (!string.IsNullOrWhiteSpace(title) && url.StartsWith("http"))
                results.Add((title, url, snippet));
        }
        return results;
    }

    private static string StripHtml(string html)
    {
        // Remove script/style blocks
        html = Regex.Replace(html, @"<(script|style)[^>]*>.*?</\1>", "",
            RegexOptions.Singleline | RegexOptions.IgnoreCase);
        // Remove tags
        html = Regex.Replace(html, @"<[^>]+>", " ");
        // Decode entities
        html = WebUtility.HtmlDecode(html);
        // Collapse whitespace
        html = Regex.Replace(html, @"\s+", " ");
        return html.Trim();
    }
}

