+        string html)
+    {
+        var results = new List<(string, string, string)>();
+
+        var linkRx = new Regex(
+            @"<a[^>]+rel=""nofollow""[^>]+href=""([^""]+)""[^>]*>(.+?)</a>",
+            RegexOptions.Singleline);
+        var snippetRx = new Regex(
+            @"<td\s+class=""result-snippet"">(.+?)</td>",
+            RegexOptions.Singleline);
+
+        var links = linkRx.Matches(html);
+        var snippets = snippetRx.Matches(html);
+
+        for (var i = 0; i < links.Count && i < snippets.Count; i++)
+        {
+            var url = WebUtility.HtmlDecode(links[i].Groups[1].Value).Trim();
+            var title = StripHtml(links[i].Groups[2].Value).Trim();
+            var snippet = StripHtml(snippets[i].Groups[1].Value).Trim();
+
+            if (!string.IsNullOrWhiteSpace(title) && url.StartsWith("http"))
+                results.Add((title, url, snippet));
+        }
+        return results;
+    }
+
+    private static string StripHtml(string html)
+    {
+        // Remove script/style blocks
+        html = Regex.Replace(html, @"<(script|style)[^>]*>.*?</\1>", "",
+            RegexOptions.Singleline | RegexOptions.IgnoreCase);
+        // Remove tags
+        html = Regex.Replace(html, @"<[^>]+>", " ");
+        // Decode entities
+        html = WebUtility.HtmlDecode(html);
+        // Collapse whitespace
+        html = Regex.Replace(html, @"\s+", " ");
+        return html.Trim();
+    }
+}

